   339→// handleGrpcStatusError sets the error source via context based on the error source provided. Regardless of its value,
   340→// a plugin downstream error is returned as both plugin and downstream errors are treated the same in Grafana.
   341→func handleGrpcStatusError(ctx context.Context, errorSource errstatus.Source, err error) error {
   342→	switch errorSource {
   343→	case backend.ErrorSourceDownstream:
   344→		innerErr := backend.WithErrorSource(ctx, backend.ErrorSourceDownstream)
   345→		if innerErr != nil {
   346→			logger.Error("Could not set downstream error source", "error", innerErr)
   347→		}
   348→		return plugins.ErrPluginRequestFailureErrorBase.Errorf("%v", err)
   349→	case backend.ErrorSourcePlugin:
   350→		errorSourceErr := backend.WithErrorSource(ctx, backend.ErrorSourcePlugin)
   351→		if errorSourceErr != nil {
   352→			logger.Error("Could not set plugin error source", "error", errorSourceErr)
   353→		}
   354→		// plugin request has failed after being sent from the Grafana server
   355→		return plugins.ErrPluginRequestFailureErrorBase.Errorf("%v", err)
   356→	}
   357→	return fmt.Errorf("%v: %w", "Failed to query data", err)
   358→}
