    15→// BackendClientInit implements an InitializeFunc for initializing a backend plugin process.
    16→//
    17→// It uses the envvars.Provider to retrieve the environment variables required for the plugin and the plugins.BackendFactoryProvider
    18→// to get fetch backend factory, which is used to form a connection to the backend plugin process.
    19→//
    20→// Note: This step does not start the backend plugin process. Please see BackendClientStarter for starting the backend plugin process.
    21→type BackendClientInit struct {
    22→	envVarProvider  envvars.Provider
    23→	backendProvider plugins.BackendFactoryProvider
    24→	log             log.Logger
    25→	tracer          trace.Tracer
    26→}
    27→
    28→// BackendClientInitStep returns a new InitializeFunc for registering a backend plugin process.
    29→func BackendClientInitStep(envVarProvider envvars.Provider,
    30→	backendProvider plugins.BackendFactoryProvider, tracer trace.Tracer) InitializeFunc {
    31→	return newBackendProcessRegistration(envVarProvider, backendProvider, tracer).Initialize
    32→}
    33→
    34→func newBackendProcessRegistration(envVarProvider envvars.Provider,
    35→	backendProvider plugins.BackendFactoryProvider, tracer trace.Tracer) *BackendClientInit {
    36→	return &BackendClientInit{
    37→		backendProvider: backendProvider,
    38→		envVarProvider:  envVarProvider,
    39→		log:             log.New("plugins.backend.registration"),
    40→		tracer:          tracer,
    41→	}
    42→}
    43→
    44→// Initialize will initialize a backend plugin client, if the plugin is a backend plugin.
    45→func (b *BackendClientInit) Initialize(ctx context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
    46→	if p.Backend {
    47→		backendFactory := b.backendProvider.BackendFactory(ctx, p)
    48→		if backendFactory == nil {
    49→			return nil, errors.New("could not find backend factory for plugin")
    50→		}
    51→
    52→		// this will ensure that the env variables are calculated every time a plugin is started
    53→		envFunc := func() []string { return b.envVarProvider.PluginEnvVars(ctx, p) }
    54→
    55→		if backendClient, err := backendFactory(p.ID, p.Logger(), b.tracer, envFunc); err != nil {
    56→			return nil, err
    57→		} else {
    58→			p.RegisterClient(backendClient)
    59→		}
    60→	}
    61→	return p, nil
    62→}
    63→
    64→// BackendClientStarter implements an InitializeFunc for starting a backend plugin process.
    65→type BackendClientStarter struct {
    66→	processManager process.Manager
    67→	log            log.Logger
    68→}
    69→
    70→// BackendProcessStartStep returns a new InitializeFunc for starting a backend plugin process.
    71→func BackendProcessStartStep(processManager process.Manager) InitializeFunc {
    72→	return newBackendProcessStarter(processManager).Start
    73→}
    74→
    75→func newBackendProcessStarter(processManager process.Manager) *BackendClientStarter {
    76→	return &BackendClientStarter{
    77→		processManager: processManager,
    78→		log:            log.New("plugins.backend.start"),
    79→	}
    80→}
    81→
    82→// Start will start the backend plugin process.
    83→func (b *BackendClientStarter) Start(ctx context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
    84→	if err := b.processManager.Start(ctx, p); err != nil {
    85→		b.log.Error("Could not start plugin backend", "pluginId", p.ID, "error", err)
    86→		return nil, (&plugins.Error{
    87→			PluginID:  p.ID,
    88→			ErrorCode: plugins.ErrorCodeFailedBackendStart,
    89→		}).WithMessage(err.Error())
    90→	}
    91→	return p, nil
    92→}
